      "rewritten_requirement": "The system shall complete the sale immediately if the customer pays with cash."
    },
    {
      "source_requirement": "If the customer chooses to pay by card or check, the system first verifies the payment.",
      "rewritten_requirement": "The system shall verify the payment if the customer chooses to pay by card or check."
    },
    {
      "source_requirement": "Once the payment is approved, the sale is completed.",
      "rewritten_requirement": "The system shall complete the sale once the payment is approved."
    },
    {
      "source_requirement": "After finishing the payment, the system returns to waiting for the next customer.",
      "rewritten_requirement": "The system shall return to waiting for the next customer after the payment has been finished."
    }
  ]
}
